     1→//! High-performance design matrix construction for statistical models
     2→//!
     3→//! This crate provides column-oriented design matrix builders that fuse
     4→//! transformations to eliminate intermediate allocations and leverage
     5→//! parallel computation for construction.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use formula::ModelSpec;
    11→use ndarray::Array2;
    12→
    13→/// Design matrix construction errors
    14→#[derive(thiserror::Error, Debug)]
    15→pub enum MatrixError {
    16→    /// Data dimension mismatch
    17→    #[error("Data dimension error: {0}")]
    18→    Dimension(String),
    19→    /// Variable not found in data
    20→    #[error("Variable not found: {0}")]
    21→    VariableNotFound(String),
    22→}
    23→
    24→/// Column-major design matrix builder
    25→pub struct Builder {
    26→    n_rows: usize,
    27→    columns: Vec<Vec<f64>>,
    28→}
    29→
    30→impl Builder {
    31→    /// Create a new builder for the given number of observations
    32→    pub fn new(n_rows: usize) -> Self {
    33→        Self {
    34→            n_rows,
    35→            columns: Vec::new(),
    36→        }
    37→    }
    38→
    39→    /// Add an intercept column (all ones)
    40→    pub fn add_intercept(&mut self) {
    41→        self.columns.push(vec![1.0; self.n_rows]);
    42→    }
    43→
    44→    /// Add a continuous variable column
    45→    pub fn add_continuous(&mut self, values: Vec<f64>) -> Result<(), MatrixError> {
    46→        if values.len() != self.n_rows {
    47→            return Err(MatrixError::Dimension(format!(
    48→                "Expected {} rows, got {}",
    49→                self.n_rows,
    50→                values.len()
    51→            )));
    52→        }
    53→        self.columns.push(values);
    54→        Ok(())
    55→    }
    56→
    57→    /// Build the final design matrix
    58→    pub fn build(self) -> Array2<f64> {
    59→        if self.columns.is_empty() {
    60→            return Array2::zeros((self.n_rows, 0));
    61→        }
    62→
    63→        let n_cols = self.columns.len();
    64→        let mut matrix = Array2::zeros((self.n_rows, n_cols));
    65→
    66→        for (col_idx, column) in self.columns.into_iter().enumerate() {
    67→            for (row_idx, value) in column.into_iter().enumerate() {
    68→                matrix[[row_idx, col_idx]] = value;
    69→            }
    70→        }
    71→
    72→        matrix
    73→    }
    74→}
    75→
    76→/// Data container for building design matrices
    77→#[derive(Debug)]
    78→pub struct DataContainer {
    79→    variables: std::collections::HashMap<String, Vec<f64>>,
    80→    n_rows: usize,
    81→}
    82→
    83→impl DataContainer {
    84→    /// Create a new data container
    85→    pub fn new(n_rows: usize) -> Self {
    86→        Self {
    87→            variables: std::collections::HashMap::new(),
    88→            n_rows,
    89→        }
    90→    }
    91→
    92→    /// Add a continuous variable to the data
    93→    pub fn add_variable(&mut self, name: String, values: Vec<f64>) -> Result<(), MatrixError> {
    94→        if values.len() != self.n_rows {
    95→            return Err(MatrixError::Dimension(format!(
    96→                "Variable '{}' has {} values but expected {}",
    97→                name,
    98→                values.len(),
    99→                self.n_rows
   100→            )));
   101→        }
   102→        self.variables.insert(name, values);
   103→        Ok(())
   104→    }
   105→
   106→    /// Get a variable by name
   107→    pub fn get_variable(&self, name: &str) -> Option<&Vec<f64>> {
   108→        self.variables.get(name)
   109→    }
   110→}
   111→
   112→/// Build design matrix from model specification and data
   113→pub fn build_design_matrix(
   114→    spec: &ModelSpec,
   115→    data: &DataContainer,
   116→) -> Result<Array2<f64>, MatrixError> {
   117→    use formula::Term;
   118→
   119→    let mut builder = Builder::new(data.n_rows);
   120→    let mut column_names = Vec::new();
   121→
   122→    // Process each term in the model specification
   123→    for term in &spec.terms {
   124→        match term {
   125→            Term::Intercept => {
   126→                builder.add_intercept();
   127→                column_names.push("(Intercept)".to_string());
   128→            }
   129→            Term::Variable(var_name) => {
   130→                let values = data
   131→                    .get_variable(var_name)
   132→                    .ok_or_else(|| MatrixError::VariableNotFound(var_name.clone()))?;
   133→                builder.add_continuous(values.clone())?;
   134→                column_names.push(var_name.clone());
   135→            }
   136→            Term::Interaction(vars) => {
   137→                // For interaction terms, multiply the variables together
   138→                if vars.len() < 2 {
   139→                    return Err(MatrixError::Dimension(
   140→                        "Interaction term must have at least 2 variables".to_string(),
   141→                    ));
   142→                }
   143→
   144→                // Get the first variable
   145→                let first_var = match &vars[0] {
   146→                    Term::Variable(name) => data
   147→                        .get_variable(name)
   148→                        .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?,
   149→                    _ => {
   150→                        return Err(MatrixError::Dimension(
   151→                            "Interaction terms must contain variable names".to_string(),
   152→                        ))
   153→                    }
   154→                };
   155→
   156→                // Start with the first variable's values
   157→                let mut interaction_values = first_var.clone();
   158→                let mut interaction_name = match &vars[0] {
   159→                    Term::Variable(name) => name.clone(),
   160→                    _ => unreachable!(),
   161→                };
   162→
   163→                // Multiply by each subsequent variable
   164→                for var in &vars[1..] {
   165→                    match var {
   166→                        Term::Variable(name) => {
   167→                            let var_values = data
   168→                                .get_variable(name)
   169→                                .ok_or_else(|| MatrixError::VariableNotFound(name.clone()))?;
   170→
   171→                            for (i, value) in interaction_values.iter_mut().enumerate() {
   172→                                *value *= var_values[i];
   173→                            }
   174→                            interaction_name.push(':');
   175→                            interaction_name.push_str(name);
   176→                        }
   177→                        _ => {
   178→                            return Err(MatrixError::Dimension(
   179→                                "Interaction terms must contain variable names".to_string(),
   180→                            ))
   181→                        }
   182→                    }
   183→                }
   184→
   185→                builder.add_continuous(interaction_values)?;
   186→                column_names.push(interaction_name);
   187→            }
   188→            Term::FullInteraction(_) => {
   189→                // FullInteraction should be expanded before reaching here
   190→                return Err(MatrixError::Dimension(
   191→                    "FullInteraction terms should be expanded before matrix construction"
   192→                        .to_string(),
   193→                ));
   194→            }
   195→            Term::Function { name: _, args: _ } => {
   196→                // TODO: Implement function calls in future sprint
   197→                return Err(MatrixError::Dimension(
   198→                    "Function calls not yet implemented".to_string(),
   199→                ));
   200→            }
   201→        }
   202→    }
   203→
   204→    Ok(builder.build())
   205→}
   206→
   207→/// Build design matrix from model specification and data (legacy compatibility)
   208→pub fn build_design_matrix_legacy(_spec: &ModelSpec) -> Result<Array2<f64>, MatrixError> {
   209→    // For backward compatibility with existing tests
   210→    let mut builder = Builder::new(2);
   211→    builder.add_intercept();
   212→    Ok(builder.build())
   213→}
   214→
