//! Statistical inference tools for computing standard errors and hypothesis tests
//!
//! This crate provides centralized tools for statistical inference, including
//! standard errors, p-values, confidence intervals, and robust covariance
//! estimators (e.g., sandwich estimators HC0-HC3).

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use ndarray::Array2;
use statrs::distribution::{ContinuousCDF, FisherSnedecor, StudentsT};

/// Statistical inference errors
#[derive(thiserror::Error, Debug)]
pub enum InferenceError {
    /// Matrix computation error
    #[error("Matrix computation error: {0}")]
    Matrix(String),
    /// Invalid degrees of freedom
    #[error("Invalid degrees of freedom: {0}")]
    DegreesOfFreedom(i32),
}

/// Compute standard errors from variance-covariance matrix
pub fn standard_errors(vcov: &Array2<f64>) -> Vec<f64> {
    let mut se = Vec::new();
    for i in 0..vcov.nrows() {
        se.push(vcov[[i, i]].sqrt());
    }
    se
}

/// Compute t-statistics given coefficients and standard errors  
pub fn t_statistics(coefficients: &[f64], std_errors: &[f64]) -> Vec<f64> {
    coefficients
        .iter()
        .zip(std_errors.iter())
        .map(|(coef, se)| coef / se)
        .collect()
}

/// Compute two-tailed p-values from t-statistics
pub fn t_test_p_values(t_stats: &[f64], df: i32) -> Vec<f64> {
    t_stats
        .iter()
        .map(|&t| {
            // Two-tailed p-value: P(|T| > |t|) = 2 * P(T > |t|)
            let abs_t = t.abs();
            2.0 * (1.0 - t_cdf(abs_t, df))
        })
        .collect()
}

/// Cumulative distribution function for Student's t-distribution using statrs
fn t_cdf(t: f64, df: i32) -> f64 {
    if df <= 0 {
        return 0.5; // Invalid df, return neutral p-value
    }

    if t.is_infinite() {
        return if t > 0.0 { 1.0 } else { 0.0 };
    }

    match StudentsT::new(0.0, 1.0, df as f64) {
        Ok(dist) => dist.cdf(t),
        Err(_) => 0.5, // Fallback for invalid parameters
    }
}

/// Compute F-statistic p-value using F-distribution
///
/// For F(f; df1, df2) = P(F ≤ f), where F follows F-distribution with df1, df2 degrees of freedom
pub fn f_test_p_value(f_stat: f64, df1: i32, df2: i32) -> f64 {
    if f_stat <= 0.0 || df1 <= 0 || df2 <= 0 {
        return 1.0;
    }

    match FisherSnedecor::new(df1 as f64, df2 as f64) {
        Ok(dist) => 1.0 - dist.cdf(f_stat), // P(F > f_stat)
        Err(_) => 1.0,                      // Fallback for invalid parameters
    }
}

/// Calculate overall F-statistic for model significance
/// Tests null hypothesis that all non-intercept coefficients are zero
pub fn model_f_statistic(rss_full: f64, rss_null: f64, df_model: usize, df_resid: usize) -> f64 {
    if df_model == 0 || df_resid == 0 || rss_full <= 0.0 {
        return 0.0;
    }

    let explained_ss = rss_null - rss_full;
    let mse_model = explained_ss / df_model as f64;
    let mse_resid = rss_full / df_resid as f64;

    if mse_resid <= 0.0 {
        return f64::INFINITY;
    }

    mse_model / mse_resid
}

