//! Link functions for generalized linear models
//!
//! This crate provides Zero-Sized Types (ZSTs) representing GLM link functions,
//! enabling compile-time dispatch for model-fitting algorithms with no runtime overhead.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

/// Trait for link functions
pub trait LinkFn {
    /// Apply the link function
    fn link(&self, mu: f64) -> f64;

    /// Apply the inverse link function  
    fn inverse_link(&self, eta: f64) -> f64;

    /// Derivative of the inverse link function
    fn mu_eta(&self, eta: f64) -> f64;
}

/// Identity link function
#[derive(Debug, Default)]
pub struct Identity;

impl LinkFn for Identity {
    fn link(&self, mu: f64) -> f64 {
        mu
    }

    fn inverse_link(&self, eta: f64) -> f64 {
        eta
    }

    fn mu_eta(&self, _eta: f64) -> f64 {
        1.0
    }
}

/// Log link function
#[derive(Debug, Default)]
pub struct Log;

impl LinkFn for Log {
    fn link(&self, mu: f64) -> f64 {
        mu.ln()
    }

    fn inverse_link(&self, eta: f64) -> f64 {
        eta.exp()
    }

    fn mu_eta(&self, eta: f64) -> f64 {
        eta.exp()
    }
}

/// Logit link function
#[derive(Debug, Default)]
pub struct Logit;

impl LinkFn for Logit {
    fn link(&self, mu: f64) -> f64 {
        (mu / (1.0 - mu)).ln()
    }

    fn inverse_link(&self, eta: f64) -> f64 {
        let exp_eta = eta.exp();
        exp_eta / (1.0 + exp_eta)
    }

    fn mu_eta(&self, eta: f64) -> f64 {
        let exp_eta = eta.exp();
        exp_eta / (1.0 + exp_eta).powi(2)
    }
}

//! Core optimization algorithms for statistical MLE
//!
//! This crate provides generic optimization algorithms tailored for statistical
//! model fitting, including IRLS, L-BFGS-B, and coordinate descent solvers.

#![forbid(unsafe_code)]
#![warn(missing_docs)]

use ndarray::Array1;

/// Optimization errors
#[derive(thiserror::Error, Debug)]
pub enum OptimError {
    /// Convergence failure
    #[error("Failed to converge after {0} iterations")]
    Convergence(usize),
    /// Numerical issue
    #[error("Numerical error: {0}")]
    Numerical(String),
}

/// Optimization result
#[derive(Debug)]
pub struct OptimResult {
    /// Final parameter estimates
    pub params: Array1<f64>,
    /// Number of iterations
    pub iterations: usize,
    /// Converged successfully
    pub converged: bool,
}

/// Iteratively Reweighted Least Squares solver
pub fn irls<F>(_objective: F, _start: Array1<f64>) -> Result<OptimResult, OptimError>
where
    F: Fn(&Array1<f64>) -> (f64, Array1<f64>),
{
    // TODO: Implement IRLS algorithm in Sprint 5
    // For now, return placeholder result for testing
    Ok(OptimResult {
        params: Array1::from(vec![1.0, 0.5]),
        iterations: 10,
        converged: true,
    })
}

